### Step 2: Add or update code snippets

**Create** `sdk/hdinsight/Azure.ResourceManager.HDInsight/tests/Samples/Sample1_Clusters.cs`:

```csharp
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Core.TestFramework;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.HDInsight;
using Azure.ResourceManager.HDInsight.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.HDInsight.Tests.Samples
{
    public class Sample1_Clusters : SamplesBase<HDInsightManagementTestEnvironment>
    {
        [Test]
        [AsyncOnly]
        public async Task CreateCluster()
        {
            #region Snippet:HDInsightCreateCluster
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = Environment.GetEnvironmentVariable("AZURE_SUBSCRIPTION_ID");
            ResourceGroupResource resourceGroup = await client.GetDefaultSubscriptionAsync()
                .GetAwaiter().GetResult()
                .GetResourceGroupAsync("<resource-group-name>");

            HDInsightClusterCollection clusters = resourceGroup.GetHDInsightClusters();

            string clusterName = "<cluster-name>";
            HDInsightClusterCreateOrUpdateContent content = new HDInsightClusterCreateOrUpdateContent
            {
                Location = Azure.Core.AzureLocation.EastUS,
                Properties = new HDInsightClusterCreateOrUpdateProperties
                {
                    ClusterVersion = "5.1",
                    OsType = HDInsightOSType.Linux,
                    ClusterDefinition = new HDInsightClusterDefinition
                    {
                        Kind = "spark",
                    },
                },
            };

            ArmOperation<HDInsightClusterResource> lro = await clusters.CreateOrUpdateAsync(
                WaitUntil.Completed, clusterName, content);
            HDInsightClusterResource cluster = lro.Value;
            Console.WriteLine($"Cluster '{cluster.Data.Name}' created");
            #endregion

#if !SNIPPET
            Assert.IsNotNull(cluster);
            Assert.AreEqual(clusterName, cluster.Data.Name);
#endif
        }

        [Test]
        [AsyncOnly]
        public async Task ListClusters()
        {
            #region Snippet:HDInsightListClusters
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceGroupResource resourceGroup = await client.GetDefaultSubscriptionAsync()
                .GetAwaiter().GetResult()
                .GetResourceGroupAsync("<resource-group-name>");

            await foreach (HDInsightClusterResource cluster in resourceGroup.GetHDInsightClusters())
            {
                Console.WriteLine(cluster.Data.Name);
            }
            #endregion
        }

        [Test]
        [AsyncOnly]
        public async Task GetCluster()
        {
            #region Snippet:HDInsightGetCluster
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceGroupResource resourceGroup = await client.GetDefaultSubscriptionAsync()
                .GetAwaiter().GetResult()
                .GetResourceGroupAsync("<resource-group-name>");

            HDInsightClusterResource cluster = await resourceGroup.GetHDInsightClusters()
                .GetAsync("<cluster-name>");
            Console.WriteLine($"Cluster state: {cluster.Data.Properties?.ClusterState}");
            #endregion
        }

        [Test]
        [AsyncOnly]
        public async Task DeleteCluster()
        {
            #region Snippet:HDInsightDeleteCluster
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceGroupResource resourceGroup = await client.GetDefaultSubscriptionAsync()
                .GetAwaiter().GetResult()
                .GetResourceGroupAsync("<resource-group-name>");

            HDInsightClusterResource cluster = await resourceGroup.GetHDInsightClusters()
                .GetAsync("<cluster-name>");
            await cluster.DeleteAsync(WaitUntil.Completed);
            Console.WriteLine("Cluster deleted");
            #endregion
        }
    }
}
```

For each snippet, the README placeholder (```` ```C# Snippet:<Name> ```` followed by closing ```` ``` ````) must match the `#region Snippet:<Name>` tag exactly.

